import{_ as l,o as i,c as n,a2 as e}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 19 章 会议与待办","description":"会议价值不在于留下多少文字，而在于把结论、责任和下一步变成可以跟踪的任务。本章介绍一种通用辅助方法，不代表公司现行会议或督办流程。 ::: warning 使用边界 录音、转写和参会信息可能包含敏感内容。使用前应确认授权范围；AI 提取的结论、责任人和时限必须由参会人员或会议负责人确认。 :::","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 19 章 会议与待办/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 19 章 会议与待办/index.md","lastUpdated":1784290813000}'),s={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 19 章 会议与待办/index.md"};function t(r,a,o,p,h,d){return i(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="第-19-章-会议与待办" tabindex="-1">第 19 章 会议与待办 <a class="header-anchor" href="#第-19-章-会议与待办" aria-label="Permalink to &quot;第 19 章 会议与待办&quot;">​</a></h1><p>会议价值不在于留下多少文字，而在于把结论、责任和下一步变成可以跟踪的任务。本章介绍一种通用辅助方法，不代表公司现行会议或督办流程。</p><div class="warning custom-block"><p class="custom-block-title">使用边界</p><p>录音、转写和参会信息可能包含敏感内容。使用前应确认授权范围；AI 提取的结论、责任人和时限必须由参会人员或会议负责人确认。</p></div><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>会前整理议题、材料清单和待决问题。</li><li>会中或会后把笔记整理为纪要草稿。</li><li>从会议材料中提取决定事项、责任人、时限和依赖。</li><li>形成待办台账、提醒清单和复盘记录。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>让每次会议至少形成四类结果：确认的结论、明确的任务、仍待决的问题、可以回查的依据。</p><h2 id="输入材料" tabindex="-1">输入材料 <a class="header-anchor" href="#输入材料" aria-label="Permalink to &quot;输入材料&quot;">​</a></h2><ul><li>会议主题、时间、参会角色和议题。</li><li>经授权使用的会议材料、笔记或转写稿。</li><li>待办台账字段和截止时间口径。</li><li>需要遵守的纪要模板与共享范围。</li></ul><h2 id="执行步骤" tabindex="-1">执行步骤 <a class="header-anchor" href="#执行步骤" aria-label="Permalink to &quot;执行步骤&quot;">​</a></h2><h3 id="会前-把讨论变成问题" tabindex="-1">会前：把讨论变成问题 <a class="header-anchor" href="#会前-把讨论变成问题" aria-label="Permalink to &quot;会前：把讨论变成问题&quot;">​</a></h3><p>WorkBuddy 先读取材料，输出“需要决定什么、缺什么材料、谁需要准备、预计形成什么结果”。不要用长篇背景占满议程。</p><h3 id="会后-区分四类信息" tabindex="-1">会后：区分四类信息 <a class="header-anchor" href="#会后-区分四类信息" aria-label="Permalink to &quot;会后：区分四类信息&quot;">​</a></h3><p>将记录拆成事实背景、讨论意见、确认结论、行动任务。意见不能自动升级为结论，模糊表述进入待确认区。</p><h3 id="建立待办台账" tabindex="-1">建立待办台账 <a class="header-anchor" href="#建立待办台账" aria-label="Permalink to &quot;建立待办台账&quot;">​</a></h3><p>每条任务至少包含任务描述、责任角色、协作角色、截止时间、验收标准、状态和来源。责任人或时限缺失时，不允许自行推断。</p><h3 id="人工复核并发布" tabindex="-1">人工复核并发布 <a class="header-anchor" href="#人工复核并发布" aria-label="Permalink to &quot;人工复核并发布&quot;">​</a></h3><p>会议负责人确认结论和待办后，再生成纪要发布版。共享前检查参会范围、敏感附件和个人信息。</p><h3 id="持续跟踪" tabindex="-1">持续跟踪 <a class="header-anchor" href="#持续跟踪" aria-label="Permalink to &quot;持续跟踪&quot;">​</a></h3><p>后续更新只改状态和进展，不改写原始结论。延期、阻塞和范围变化应留下原因与确认记录。</p><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>假设召开一次“办公设备集中盘点准备会”。合成材料包含三项议题和五段笔记。WorkBuddy 可整理出两项确认事项、三项待办和一个待决问题；具体责任人和完成时间仍由会议负责人确认。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请根据当前目录中的会议材料，生成纪要草稿和待办台账。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>会议主题：{主题}</span></span>
<span class="line"><span>材料范围：{文件名}</span></span>
<span class="line"><span>纪要模板：{模板文件或“未提供”}</span></span>
<span class="line"><span>台账字段：任务、责任角色、协作角色、截止时间、验收标准、状态、来源</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要求：</span></span>
<span class="line"><span>1. 区分事实背景、讨论意见、确认结论、行动任务和待决问题；</span></span>
<span class="line"><span>2. 不把个人观点写成会议结论；</span></span>
<span class="line"><span>3. 缺失的责任人、时限和验收标准标记“待确认”；</span></span>
<span class="line"><span>4. 每条结论和任务标注来源材料或记录位置；</span></span>
<span class="line"><span>5. 先输出预览，等我确认后再生成文件；</span></span>
<span class="line"><span>6. 不发送消息、不创建外部任务、不覆盖原始材料。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>会议记录是否经过授权使用。</li><li>结论是否真正形成，而不是讨论意见。</li><li>责任人、完成时间和验收标准是否明确。</li><li>纪要接收范围和附件是否合适。</li><li>变更和延期是否得到有权限人员确认。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>纪要草稿：结论明确，意见与结论分开。</li><li>待办台账：每条任务可执行、可验收、可追踪。</li><li>待决问题清单：说明缺什么、由谁确认。</li><li>发布检查表：接收范围、附件和敏感信息已检查。</li></ul><h2 id="常见弯路" tabindex="-1">常见弯路 <a class="header-anchor" href="#常见弯路" aria-label="Permalink to &quot;常见弯路&quot;">​</a></h2><ul><li><strong>按发言顺序复述</strong>：信息很多，但找不到结论。应按议题和结果重组。</li><li><strong>默认补全责任人和日期</strong>：容易产生错误承诺。缺失项必须显式待确认。</li><li><strong>纪要发出就算结束</strong>：没有台账和状态更新，任务仍会失联。</li></ul><h2 id="安全边界" tabindex="-1">安全边界 <a class="header-anchor" href="#安全边界" aria-label="Permalink to &quot;安全边界&quot;">​</a></h2><ul><li>未经允许不录音、不转写、不扩大会议材料可见范围。</li><li>不自动向外发送纪要，不代表负责人创建承诺。</li><li>不删除原始记录，不用 AI 草稿替代正式确认版本。</li><li>不把本章方法描述为公司的正式会议制度。</li></ul><h2 id="可复用资产" tabindex="-1">可复用资产 <a class="header-anchor" href="#可复用资产" aria-label="Permalink to &quot;可复用资产&quot;">​</a></h2><ul><li>会前议题卡。</li><li>纪要结构模板。</li><li>待办台账字段模板。</li><li>待决问题清单。</li><li>发布与复盘检查表。</li></ul>`,34)])])}const b=l(s,[["render",t]]);export{u as __pageData,b as default};
